(window.webpackJsonp=window.webpackJsonp||[]).push([[197],{824:function(n,t){n.exports='\x3c!-- \ntitle: Nginx\nsort: \n--\x3e \n\n# Nginx入门\n\n> [OpenResty](http://openresty.org/cn/)\n\n## 配置\n\n```bash\nvim /etc/nginx/sites-enabled/default \nnginx -s reload\n```\n\n## 基础\n\n```nginx\nlocation /test {\n\techo "fzf";\t\t# 输出内容\n    proxy_pass https://baidu.com/;\t\t# 重定向\n}\n```\n\n```nginx\n# 负载均衡 权重\nupstream group1{\n\tserver 192.168.0.1:80 weight=2;\n\tserver 192.168.0.1:8080 weight=1;\n}\n\nserver{\n    location /test/{\n        # 随机重定向到两个网页\n        proxy_pass http://group1/;\n    }\n}\n```\n\n## 实例\n\n- 作为文件服务器使用\n\n```nginx\nlocation /app {\n    # 遍历目录\n    autoindex on;\n    # 文件大小显示\n    autoindex_exact_size off;\n    # 显示服务器时间\n    autoindex_localtime on;\n    # 中文文件夹转码\n    charset utf-8;\n}\n```\n\n'}}]);